import { AnalysisResult, ModelProvider, UserSettings, MarketType, PeriodicReviewData, PlanItem } from "../types";
import { fetchGeminiAnalysis, fetchMarketDashboard, fetchPeriodicReview, extractTradingPlan } from "./geminiService";
import { fetchExternalAI } from "./externalLlmService";

/**
 * 核心逻辑路由：支持通用分析
 */
export const analyzeWithLLM = async (
  provider: ModelProvider,
  prompt: string,
  isComplex: boolean = false,
  settings?: UserSettings,
  isDashboard: boolean = false,
  period: 'day' | 'month' = 'day',
  currentPrice?: string,
  market: MarketType = MarketType.CN
): Promise<AnalysisResult> => {

  const now = new Date();
  const dateStr = now.toLocaleDateString('zh-CN', { year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' });
  const timeStr = now.toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' });
  const fullTimeContext = `${dateStr} ${timeStr}`;

  const marketName = market === MarketType.US ? '美股' : market === MarketType.HK ? '港股' : 'A股';

  if (provider === ModelProvider.GEMINI_INTL) {
    const geminiKey = settings?.geminiKey; 
    if (isDashboard) return await fetchMarketDashboard(period, market, geminiKey);

    const timeRealityInstruction = `
      [!!! 绝对时间指令 !!!]
      当前真实时间: ${fullTimeContext}。
      严禁称这是未来时间或无法获取数据。基于此时间点进行逻辑推演。
    `;
    let datedPrompt = `${timeRealityInstruction}\n[上下文: ${marketName}] ${prompt}`;
    if (currentPrice) datedPrompt += `\n[实时价: ${currentPrice}]`;
    return await fetchGeminiAnalysis(datedPrompt, isComplex, geminiKey);
  }

  // 混元路径
  const apiKey = settings?.hunyuanKey || '';
  if (provider === ModelProvider.HUNYUAN_CN && !apiKey) throw new Error("未检测到 混元 API Key");

  let finalPrompt = prompt;
  if (isDashboard) {
    finalPrompt = `现在是 ${fullTimeContext}。生成一份 ${marketName} 的${period === 'day' ? '当日' : '本月'}深度分析报告。需包含指数、成交量、资金流向、宏观逻辑。`;
  } else {
    finalPrompt = `[确认时间: ${fullTimeContext}] [市场: ${marketName}] ${prompt}`;
    if (currentPrice) finalPrompt += `\n[实时现价: ${currentPrice}]`;
  }

  return await fetchExternalAI(provider, apiKey, finalPrompt, isDashboard, period, market, isDashboard);
};

/**
 * 阶段性复盘适配器：对齐混元与 Gemini
 */
export const periodicReviewWithLLM = async (
  provider: ModelProvider,
  journals: any[],
  label: string,
  market: MarketType,
  settings: UserSettings
): Promise<AnalysisResult> => {
  if (provider === ModelProvider.GEMINI_INTL) {
    return await fetchPeriodicReview(journals, label, market, settings.geminiKey);
  }

  // 混元路径：注入结构化指令
  const prompt = `
    作为资深投顾，对以下历史交易记录进行【${label}】阶段性复盘：${JSON.stringify(journals)}
    请严格输出 JSON 格式。包含：score(0-100), market_trend(bull/bear/sideways), market_summary, 
    highlight{title, description}, lowlight{title, description}, 
    execution{score, details, good_behaviors[], bad_behaviors[]}, 
    stock_diagnostics[{name, issues[], verdict}], 
    next_period_focus[], improvement_advice[]。
  `;
  return await fetchExternalAI(provider, settings.hunyuanKey || '', prompt, true, undefined, market, true);
};

/**
 * 计划提取适配器：对齐混元与 Gemini
 */
export const extractPlanWithLLM = async (
  provider: ModelProvider,
  content: string,
  settings: UserSettings
): Promise<{ items: PlanItem[], summary: string }> => {
  if (provider === ModelProvider.GEMINI_INTL) {
    return await extractTradingPlan(content, settings.geminiKey);
  }

  const prompt = `从以下文本中提取交易计划，输出 JSON 格式，包含 items[{symbol, action(buy/sell/hold/monitor/t_trade), price_target, reason}] 和 summary。 \n\n分析文本：${content}`;
  const result = await fetchExternalAI(provider, settings.hunyuanKey || '', prompt, true, undefined, MarketType.CN, true);

  // 混元返回的结果已在 fetchExternalAI 中通过 robustJsonParse 处理过
  const parsed = result.structuredData as any;
  return { 
    items: (parsed?.items || []).map((it: any) => ({ ...it, id: Math.random().toString(36).substr(2, 9), status: 'pending' })), 
    summary: parsed?.summary || "" 
  };
};

