  };

  const handlePeriodicReview = async (period: 'week' | 'month' | 'all') => {
    if (journal.length < 1) {
      setError("历史记录不足，无法进行阶段性复盘。");
      return;
    }
    setLoading(true);
    setError(null);
    setAnalysisResult(null); 
    setPeriodicResult(null);
