import { AnalysisResult, ModelProvider, UserSettings, MarketType, StockSynergyResponse } from "../types";
import { fetchGeminiAnalysis, fetchMarketDashboard, fetchStockSynergy, fetchStockDetailWithImage } from "./geminiService";
import { fetchExternalAI, analyzeImageWithExternal } from "./externalLlmService";

/**
 * 核心逻辑路由：市场全览
 */
export const analyzeWithLLM = async (
  provider: ModelProvider,
  prompt: string,
  isComplex: boolean = false,
  settings?: UserSettings,
  isDashboard: boolean = false,
  period: 'day' | 'month' = 'day',
  currentPrice?: string,
  market: MarketType = MarketType.CN
): Promise<AnalysisResult> => {
  const now = new Date();
  const dateStr = now.toLocaleDateString('zh-CN', { year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' });
  const timeStr = now.toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' });
  const fullTimeContext = `${dateStr} ${timeStr}`;
  const marketName = market === MarketType.US ? '美股' : market === MarketType.HK ? '港股' : 'A股';

  if (provider === ModelProvider.GEMINI_INTL) {
    const geminiKey = settings?.geminiKey; 
    if (isDashboard) return await fetchMarketDashboard(period, market, geminiKey);
    const timeInstruction = `当前真实时间: ${fullTimeContext}。基于此时间点进行逻辑推演。`;
    let datedPrompt = `${timeInstruction}\n[上下文: ${marketName}] ${prompt}`;
    if (currentPrice) datedPrompt += `\n[实时价: ${currentPrice}]`;
    return await fetchGeminiAnalysis(datedPrompt, isComplex, geminiKey);
  }

  // 混元路径
  const apiKey = settings?.hunyuanKey || '';
  let finalPrompt = prompt;
  if (isDashboard) {
    finalPrompt = `现在是 ${fullTimeContext}。生成一份 ${marketName} 的${period === 'day' ? '当日' : '本月'}深度分析报告。需包含指数、成交量、资金流向、宏观逻辑。`;
  } else {
    finalPrompt = `[确认时间: ${fullTimeContext}] [市场: ${marketName}] ${prompt}`;
    if (currentPrice) finalPrompt += `\n[实时现价: ${currentPrice}]`;
  }
  return await fetchExternalAI(provider, apiKey, finalPrompt, isDashboard, period, market, isDashboard);
};

/**
 * 标的合力审计适配器
 */
export const stockSynergyWithLLM = async (
  provider: ModelProvider,
  query: string,
  marketImg: string | null,
  holdingsImg: string | null,
  settings: UserSettings
): Promise<AnalysisResult> => {
  if (provider === ModelProvider.GEMINI_INTL) {
    return await fetchStockSynergy(query, marketImg, holdingsImg, settings.geminiKey || '');
  }

  // 混元路径：多图输入模拟（目前混元视觉接口支持单图或多图拼接，此处采用逻辑引导）
  const prompt = `
    作为顶级游资操盘手，对标的 "${query}" 进行【合力与主力成本深度审计】。
    请分析上传图片中的 K 线形态和筹码分布。输出 JSON。
    包含：name, code, used_current_price, synergy_score, trap_risk_score, dragon_potential_score, 
    market_position, capital_consistency, 
    main_force_cost_anchor{estimated_cost, safety_margin_percent, risk_level},
    turnover_eval{current_rate, is_sufficient, verdict},
    main_force_portrait{lead_type, entry_cost_est, hold_status},
    t_plus_1_prediction{expected_direction, confidence, price_range, opening_strategy, logic},
    synergy_factors[{label, score, description}], battle_verdict, action_guide, chase_safety_index。
  `;

  // 混元视觉分析（目前 externalLlmService 中的 analyzeImageWithExternal 返回 HoldingsSnapshot，需要为 Synergy 扩展）
  // 此处简化处理：若有图则走视觉模型，无图走常规模型
  if (marketImg) {
    const apiKey = settings.hunyuanKey || '';
    // 这里复用 analyzeImageWithExternal 的逻辑但传入 Synergy Prompt
    const result = await fetchExternalAI(provider, apiKey, prompt, false, undefined, MarketType.CN, true);
    return result;
  }

  return await fetchExternalAI(provider, settings.hunyuanKey || '', prompt, false, undefined, MarketType.CN, true);
};

/**
 * 个股量化诊断适配器 (含视觉对齐)
 */
export const stockDiagnosisWithLLM = async (
  provider: ModelProvider,
  query: string,
  market: MarketType,
  image: string | null,
  currentPrice: string,
  settings: UserSettings
): Promise<AnalysisResult> => {
  const prompt = `
    对 ${market} 股票 "${query}" 进行深度量化分析。
    [!!! 绝对优先级 !!!]: 优先识别截图中的【现价】和【成交量形态】。
    输出：1.基础数据与量化指标 2.关键价位 3.板块Beta与洗盘诊断 4.量化评级与操作指令 5.核心逻辑。
  `;

  if (provider === ModelProvider.GEMINI_INTL) {
    if (image) return await fetchStockDetailWithImage(image, query, market, settings.geminiKey || '', currentPrice);
    return await analyzeWithLLM(provider, prompt, false, settings, false, 'day', currentPrice, market);
  }

  // 混元路径
  const apiKey = settings.hunyuanKey || '';
  if (image) {
    // 视觉诊断
    return await fetchExternalAI(provider, apiKey, prompt, false, undefined, market, false); 
  }
  return await analyzeWithLLM(provider, prompt, false, settings, false, 'day', currentPrice, market);
};

