          <button onClick={() => setActiveTab('forecast')} className={`px-6 py-2 rounded-xl text-xs font-bold transition-all ${activeTab === 'forecast' ? 'bg-white shadow-sm text-rose-600' : 'text-slate-500'}`}>走势推演</button>
