export const extractPlanWithLLM = async (
  provider: ModelProvider,
  content: string,
  settings: UserSettings
): Promise<{ items: PlanItem[], summary: string }> => {
  const jsonSchemaPrompt = `
    从以下复盘报告中提取结构化计划。
    输出必须为严格的 JSON 格式，不得包含任何 Markdown 标记：
    {
      "items": [
